// ============================================================
// RELAY-010 — Étape 1 : Validation source et rate limiting
// ============================================================
// Ce nœud vérifie :
//   1. Que la requête vient du relay Python (flags _relay_sig_ok + _relay_validated_at)
//   2. Que le timestamp est récent (anti-replay, fenêtre 5min)
//   3. Rate limiting par expéditeur (anti-spam)
// ============================================================

const raw  = $input.first().json;
const body = raw.body || raw;
const ts   = new Date().toISOString();
const store = $getWorkflowStaticData('global');

// ── 1. VÉRIFICATION FLAGS RELAY PYTHON ──────────────────────
const relaySigOk       = body._relay_sig_ok === true;
const relayValidatedAt = String(body._relay_validated_at || '').trim();
const relayVersion     = String(body._relay_version     || '').trim();
const relayHmac        = String(body._relay_hmac        || '').trim();

if (!relaySigOk || !relayValidatedAt || !relayVersion.startsWith('RELAY-010')) {
  console.log('[SECURITY][RELAY-010] Requête sans flags relay valides — ' + ts);
  return [{ json: {
    _valid    : false,
    error     : 'UNVALIDATED_SOURCE',
    message   : 'Requête non passée par le relay Python RELAY-010',
    timestamp : ts
  }}];
}

// ── 2. VÉRIFICATION TIMESTAMP ANTI-REPLAY (5 min) ───────────
try {
  const relayTs = new Date(relayValidatedAt).getTime();
  const nowTs   = Date.now();
  const diffSec = Math.abs(nowTs - relayTs) / 1000;
  if (diffSec > 300) {
    console.log('[SECURITY][RELAY-010] Timestamp expiré: ' + diffSec.toFixed(0) + 's — ' + ts);
    return [{ json: {
      _valid   : false,
      error    : 'REPLAY_ATTACK',
      message  : 'Timestamp relay expiré (' + diffSec.toFixed(0) + 's) — possible replay',
      timestamp: ts
    }}];
  }
} catch(e) {
  return [{ json: {
    _valid   : false,
    error    : 'INVALID_TIMESTAMP',
    message  : 'Format timestamp relay invalide',
    timestamp: ts
  }}];
}

// ── 3. VÉRIFICATION FORMAT HMAC (32 hex chars) ──────────────
if (relayHmac && !/^[0-9a-f]{32}$/.test(relayHmac)) {
  console.log('[SECURITY][RELAY-010] Format HMAC invalide — ' + ts);
  return [{ json: {
    _valid   : false,
    error    : 'INVALID_HMAC_FORMAT',
    message  : 'Format _relay_hmac invalide (attendu: 32 hex)',
    timestamp: ts
  }}];
}

// ── 4. RATE LIMITING PAR EXPÉDITEUR (10 msg/min) ────────────
const sender  = String(body.From || '').replace('whatsapp:', '').trim();
const safeKey = 'RL_' + sender.replace(/[^0-9+]/g, '_').substring(0, 30);
const now     = Date.now();
const cutoff  = now - 60000;

let rl = { ts: [] };
try { rl = JSON.parse(store[safeKey] || '{}'); } catch(e) {}
rl.ts = (rl.ts || []).filter(t => t > cutoff);

if (rl.ts.length >= 10) {
  const retryAfter = Math.ceil((rl.ts[0] + 60000 - now) / 1000);
  console.log('[RELAY-010] Rate limit expéditeur: ' + sender + ' — ' + ts);
  return [{ json: {
    _valid      : false,
    error       : 'RATE_LIMITED',
    message     : 'Trop de messages — réessayer dans ' + retryAfter + 's',
    retry_after : retryAfter,
    timestamp   : ts
  }}];
}
rl.ts.push(now);
store[safeKey] = JSON.stringify(rl);

// ── 5. EXTRACTION DONNÉES PROPRES ───────────────────────────
const safeBody = String(body.Body || '').replace(/[\x00-\x1f]/g, ' ').trim().substring(0, 200);
const safeFrom = String(body.From || '').trim().substring(0, 50);
const msgSid   = String(body.MessageSid || '').trim().substring(0, 40);
const channel  = safeFrom.startsWith('whatsapp:') ? 'whatsapp' : 'sms';

console.log('[RELAY-010] Message validé — De: ' + safeFrom.substring(0, 20) +
  ' — Body: ' + safeBody.substring(0, 30) + '...');

return [{ json: {
  _valid            : true,
  _relay_sig_ok     : true,
  _relay_validated_at: relayValidatedAt,
  _relay_version    : relayVersion,
  _relay_hmac       : relayHmac,
  Body              : safeBody,
  From              : safeFrom,
  MessageSid        : msgSid,
  channel           : channel,
  timestamp         : ts
}}];

// ============================================================
// RELAY-010 — Étape 2 : Vérification HMAC interne
// ============================================================
// Recompute le HMAC-SHA256 avec la même formule que relay010.py
// pour confirmer que le message n'a pas été altéré en transit.
//
// NOTE : sur n8n Cloud, require('crypto') NE FONCTIONNE PAS.
// On utilise l'API SubtleCrypto (disponible en n8n ≥1.30)
// via un workaround synchrone basé sur la comparaison directe.
//
// WORKAROUND FIABLE POUR N8N CLOUD :
// Comme SubtleCrypto est async et que les nœuds Code n8n sont
// synchrones, on fait une vérification de cohérence structurelle
// et on délègue la vérification HMAC au nœud HTTP Supabase Edge.
// ============================================================

const input = $input.first().json;
const ts    = new Date().toISOString();

// Vérifications structurelles synchrones (pas besoin de HMAC pour ça)
const body = String(input.Body || '').trim();
const from = String(input.From || '').trim();

// Regex strict sur le format du message WhatsApp
// Format valide : BF-OUI-123456, PH-NON-654321, etc.
const OTP_PATTERN = /^(BF|PH)-(OUI|NON)-(\d{6})$/;
const bodyUpper = body.toUpperCase();
const formatValid = OTP_PATTERN.test(bodyUpper);

// Vérification expéditeur autorisé
const senderRaw = from.replace('whatsapp:', '').trim();
const AUTHORIZED_PHONES = [];
if ($vars.ANALYST_L1_PHONE) AUTHORIZED_PHONES.push(String($vars.ANALYST_L1_PHONE).trim());
if ($vars.ANALYST_L2_PHONE) AUTHORIZED_PHONES.push(String($vars.ANALYST_L2_PHONE).trim());

const senderAuthorized = AUTHORIZED_PHONES.length > 0 && AUTHORIZED_PHONES.includes(senderRaw);

// Log de sécurité
if (!senderAuthorized) {
  console.log('[SECURITY][RELAY-010] Expéditeur non autorisé: ' + senderRaw + ' — ' + ts);
}
if (!formatValid) {
  console.log('[RELAY-010] Format message non reconnu (sera IGNORED par RESP-006): ' + bodyUpper.substring(0, 30));
}

// Analyse IA optionnelle : on flagge si le message semble suspect
// (injection tentée, caractères hors ASCII, longueur anormale)
const rawLength = body.length;
const hasNonAscii = /[^\x20-\x7E]/.test(body);
const looksLikeInjection = /(SELECT|DROP|INSERT|UPDATE|script|eval|__proto__)/i.test(body);

const suspicionScore =
  (rawLength > 50    ? 1 : 0) +
  (hasNonAscii       ? 2 : 0) +
  (looksLikeInjection? 5 : 0) +
  (!formatValid && rawLength > 0 ? 1 : 0);

if (suspicionScore >= 5) {
  console.log('[SECURITY][RELAY-010] Message suspect (score=' + suspicionScore + ') — ' + body.substring(0,40));
}

return [{ json: {
  ...input,
  _hmac_check        : 'STRUCTURAL_OK',
  _format_valid      : formatValid,
  _sender_authorized : senderAuthorized,
  _suspicion_score   : suspicionScore,
  _body_upper        : bodyUpper,
  timestamp          : ts
}}];

// Log de l'erreur de forward vers RESP-006
const input = $input.first().json;
const ts    = new Date().toISOString();

console.log('[RELAY-010][ERROR] Forward vers RESP-006 échoué — ' + ts);
console.log('[RELAY-010][ERROR] Réponse: ' + JSON.stringify(input).substring(0, 200));

return [{ json: {
  ...input,
  _forward_error: true,
  _forward_ts   : ts
}}];
